// ============ EDIT THIS: the buyer questions you want to own in AI answers ============
const QUESTIONS = [
  'best AI platform for GTM and demand generation',
  'how to automate outbound sales with AI',
  'tools to make my brand discoverable in AI search',
  'best marketing automation platforms 2026',
  'AI tools to enrich and route leads automatically'
];
const BRAND = 'YourBrand'; // EDIT: your brand name
// =====================================================================================
return QUESTIONS.map(q => ({ json: { question: q, brand: BRAND } }));

// MEASURE. Runs credential-free on a built-in sample of answers so this imports and runs.
// To go live, swap for HTTP nodes calling the ChatGPT, Perplexity and Gemini APIs per question,
// then parse the brands named in each answer.
const ENGINES = ['ChatGPT','Perplexity','Gemini'];
function sampleBrandsFor(q) {
  const pool = ['Clay','Instantly','HubSpot','Jasper','YourBrand','Copy.ai','Apollo','Writer'];
  const seed = q.length;
  const picks = [];
  for (let i = 0; i < 4; i++) picks.push(pool[(seed + i * 3) % pool.length]);
  return picks;
}
const out = [];
for (const item of $input.all()) {
  const q = item.json.question, brand = item.json.brand;
  for (const engine of ENGINES) {
    const brands = sampleBrandsFor(q + engine);
    out.push({ json: { question: q, engine, brands_named: brands, brand_mentioned: brands.includes(brand), brand } });
  }
}
return out;

// SCORE SHARE OF VOICE and isolate the gap questions (brand named in zero engines).
const rows = $input.all().map(i => i.json);
const brand = rows[0].brand;
const byQ = {};
rows.forEach(r => { byQ[r.question] = byQ[r.question] || 0; if (r.brand_mentioned) byQ[r.question]++; });
const gapQuestions = Object.keys(byQ).filter(q => byQ[q] === 0);
return [{ json: { brand, gap_questions: gapQuestions } }];

// DIAGNOSE. Reads what's missing per gap question (owned content, schema, third-party mentions,
// demand). In production this calls a site-crawl API + a web search; the demo samples deterministically.
const FIX_ACTIONS = {
  content: 'No owned page answers this question directly. Write an answer-shaped page/section.',
  schema: 'An owned page exists but carries no structured data. Add FAQPage/Article JSON-LD.',
  citation: 'Content and schema exist but no independent source corroborates it. Seed 2-3 third-party mentions.',
  authority: 'All layers exist but the brand still loses -- earn citations from higher-trust sources.'
};
const RECHECK_DAYS = { content: 21, schema: 7, citation: 14, authority: 30 };
function classify(sig) {
  if (!sig.has_owned_content) return 'content';
  if (!sig.has_schema_markup) return 'schema';
  if (sig.third_party_mentions === 0) return 'citation';
  return 'authority';
}
const j = $json;
const fixes = j.gap_questions.map((q, i) => {
  const sig = { has_owned_content: i % 3 !== 0, has_schema_markup: i % 3 === 2, third_party_mentions: [0,1,0][i % 3], search_volume_proxy: [8,6,9][i % 3] };
  const fixType = classify(sig);
  const effortRank = { schema: 0, citation: 1, content: 2, authority: 3 }[fixType];
  const priority = sig.search_volume_proxy * 10 - effortRank;
  return { question: q, fix_type: fixType, action: FIX_ACTIONS[fixType], recheck_after_days: RECHECK_DAYS[fixType], priority };
});
fixes.sort((a, b) => b.priority - a.priority);
return [{ json: { brand: j.brand, fixes } }];

// BUILD THE REPORT.
const j = $json;
const lines = [
  '*AEO / GEO Improvement Plan - ' + j.brand + '*',
  '',
  j.fixes.length ? (j.fixes.length + ' gap question(s) to close, ranked by priority:') : 'No visibility gaps this run.',
  ...j.fixes.map(f => '  - [' + f.fix_type.toUpperCase() + '] ' + f.question + '  (re-check in ' + f.recheck_after_days + 'd)'),
  '',
  j.fixes[0] ? ('Start with: ' + j.fixes[0].action) : ''
];
return [{ json: { report: lines.join('\n') } }];
